import styled, { css } from 'styled-components'

import { useAppSelector } from '../../app-state'
import { OrderSummary } from '../../components/ShoppingCart'
import { selectCartItems } from '../../app-state/cart'
import { breakpoints } from '../../styles/breakpoints'
import { Heading } from '../../components/typography/Heading'
import { PageTemplate } from '../../templates/PageTemplate'

import { MultiStepForm } from './components/registration-form/MultiStepForm'

const OrderDetailsContainer = styled.div`
  width: 100%;
  margin-bottom: 4rem;

  @media ${breakpoints.M} {
    width: 420px;
  }
`

const TopContainer = styled.div(
  ({ theme: { color, spacing } }) => css`
    padding-top: ${spacing.xl};
    margin-bottom: ${spacing.s};
    min-height: 260px;
    background: ${color.checkoutTopBackground};

    @media ${breakpoints.M} {
      padding-top: ${spacing.xxl};
      min-height: 300px;
    }
  `
)

const BottomContainer = styled.div`
  display: flex;
  margin-top: -12rem !important;
  justify-content: center;
  flex-direction: column-reverse;
  align-items: flex-start;

  @media ${breakpoints.S} {
    margin-top: -10rem !important;
    flex-direction: row;
  }
`

const StyledHeading = styled(Heading)`
  margin: 0 auto;
`

const ContentContainer = styled.div(
  ({ theme: { color, spacing } }) => css`
    min-height: 100vh;
    padding-bottom: ${spacing.xxl};
    background: ${color.checkoutBottomBackground};
  `
)

export const CheckoutPage = () => {
  const cartItems = useAppSelector(selectCartItems)

  return (
    <PageTemplate type="basic">
      <ContentContainer>
        <TopContainer>
          <StyledHeading level={2} className="container">
            Checkout
          </StyledHeading>
        </TopContainer>
        <BottomContainer className="container">
          <MultiStepForm />
          <OrderDetailsContainer>
            <OrderSummary cartItems={cartItems} />
          </OrderDetailsContainer>
        </BottomContainer>
      </ContentContainer>
    </PageTemplate>
  )
}

import * as React from 'react'
import styled, { css } from 'styled-components'

import { Button } from '../Button'
import { Body, Heading } from '../typography'

const ErrorContainer = styled.div(
  ({ theme: { spacing } }) => css`
    margin: 0 auto;
    padding: ${spacing.l} 0;
    display: flex;
    align-items: center;
    flex-direction: column;
  `
)

const ImageContainer = styled.div(
  ({ theme: { spacing } }) => css`
    text-align: center;
    margin-top: ${spacing.m};
    display: flex;
    justify-content: center;
    width: 100%;
  `
)

type ErrorBlockProps = {
  title: string
  image: React.ReactNode
  body: string
  buttonText: string
  onButtonClick: () => void
}

export const ErrorBlock = ({ title, image, body, buttonText, onButtonClick }: ErrorBlockProps) => (
  <ErrorContainer>
    <Heading level={2}>{title}</Heading>
    <ImageContainer>{image}</ImageContainer>
    <Body>{body}</Body>
    <Button onClick={onButtonClick}>{buttonText}</Button>
  </ErrorContainer>
)

import { combineReducers, configureStore } from '@reduxjs/toolkit'

import { reducer as cart } from './cart'
import { reducer as order } from './order'

export const rootReducer = combineReducers({
  cart,
  order,
})

export const store = configureStore({
  reducer: rootReducer,
})

export type AppDispatch = typeof store.dispatch
export type RootState = ReturnType<typeof store.getState>

import * as React from 'react'
import styled from 'styled-components'

import { Header, HeaderComponent } from '../components/Header/Header'
import { Footer } from '../components/Footer/Footer'

const Container = styled.div`
  min-height: calc(100vh - 200px);
`

type PageTemplateProperties = {
  type?: 'default' | 'sticky-header' | 'basic'
}

export const PageTemplate: React.FC<React.PropsWithChildren<PageTemplateProperties>> = ({
  type = 'default',
  children,
}) => {
  switch (type) {
    case 'sticky-header': {
      return (
        <>
          <Header sticky />
          <Container>{children}</Container>
          <Footer />
        </>
      )
    }
    case 'basic': {
      return (
        <>
          <HeaderComponent logoOnly />
          <Container>{children}</Container>
        </>
      )
    }
  }

  return (
    <>
      <Header />
      <Container>{children}</Container>
      <Footer />
    </>
  )
}

import styled from 'styled-components'
import { useNavigate } from 'react-router-dom'
import Carousel, { type ArrowProps, type CarouselProps } from 'react-multi-carousel'

import { useFetchRestaurants } from '../../../../api/hooks'
import { IconButton } from '../../../../components/IconButton'
import { PageSection } from '../../../../components/PageSection'
import { RestaurantCard, RestaurantCardSkeleton } from '../../../../components/RestaurantCard'
import { Restaurant } from '../../../../types'
import { isMobile } from '../../../../helpers'

const PreviousButton = styled(IconButton)`
  position: absolute;
  left: 0;
`

const NextButton = styled(IconButton)`
  position: absolute;
  right: 0;
`

type RestaurantsSectionProps = {
  title: string
}

const CustomArrow = (props: Partial<CarouselProps & ArrowProps> & { isNext?: boolean }) => {
  // filter out unnecessary props coming from react-multi-carousel
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { carouselState, rtl, isNext, ...rest } = props
  return isNext ? (
    <NextButton name="arrow-right" {...rest} />
  ) : (
    <PreviousButton name="arrow-left" {...rest} />
  )
}

export const RestaurantsSection = ({ title }: RestaurantsSectionProps) => {
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurants()

  const isOnMobile = isMobile()
  return (
    <PageSection title={title}>
      <Carousel
        draggable={isOnMobile}
        partialVisible={isOnMobile}
        customLeftArrow={<CustomArrow />}
        customRightArrow={<CustomArrow isNext />}
        responsive={{
          desktop: {
            breakpoint: { max: 5000, min: 1024 },
            items: 3,
            slidesToSlide: 3,
          },
          tablet: {
            breakpoint: { max: 1024, min: 464 },
            items: 2,
            paritialVisibilityGutter: 50,
          },
          mobile: {
            breakpoint: { max: 464, min: 0 },
            items: 1,
            paritialVisibilityGutter: 30,
          },
        }}
        containerClass="carousel-container"
        removeArrowOnDeviceType={['tablet', 'mobile']}
        itemClass="carousel-item"
      >
        {status === 'loading'
          ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
          : restaurants.map((restaurant: Restaurant, index: number) => (
              <RestaurantCard
                key={restaurant.name + index}
                {...restaurant}
                onClick={() => navigate(`/restaurants/${restaurant.id}`)}
              />
            ))}
      </Carousel>
    </PageSection>
  )
}

