 1→import { createSlice, CaseReducer, PayloadAction } from '@reduxjs/toolkit'
 2→
 3→import { ShopItem } from '../../types'
 4→export interface CartItem extends ShopItem {
 5→  quantity: number
 6→}
 7→
 8→export type CartState = {
 9→  visible: boolean
10→  items: CartItem[]
11→}
12→
13→const toggleVisibility: CaseReducer<CartState> = (state) => {
14→  state.visible = !state.visible
15→}
16→
17→const clearCart: CaseReducer<CartState> = (state) => {
18→  state.visible = false
19→  state.items = []
20→}
21→
22→const clearItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
23→  state.items = state.items.filter((item) => item.id !== action.payload.id)
24→}
25→
26→const removeItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
27→  const existingCartItem = state.items.find((item) => item.id === action.payload.id)
28→
29→  if (!existingCartItem) return
30→
31→  if (existingCartItem.quantity === 1) {
32→    state.items = state.items.filter((item) => item.id !== action.payload.id)
33→  } else {
34→    existingCartItem.quantity -= 1
35→  }
36→}
37→
38→const saveItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
39→  const existingCartItem = state.items.find((item) => item.id === action.payload.id) as CartItem
40→
41→  if (existingCartItem) {
42→    existingCartItem.quantity = action.payload.quantity
43→  } else {
44→    state.items.push(action.payload)
45→  }
46→}
47→
48→const initialState: CartState = {
49→  visible: false,
50→  items: [],
51→}
52→
53→const cartSlice = createSlice({
54→  name: 'cart',
55→  initialState,
56→  reducers: {
57→    toggleVisibilityAction: toggleVisibility,
58→    saveItemAction: saveItem,
59→    clearItemAction: clearItem,
60→    removeItemAction: removeItem,
61→    clearCartAction: clearCart,
62→  },
63→})
64→
65→// Extract the action creators object and the reducer
66→export const { actions, reducer } = cartSlice
67→
68→// Extract and export each action creator by name
69→export const {
70→  toggleVisibilityAction,
71→  saveItemAction,
72→  clearItemAction,
73→  removeItemAction,
74→  clearCartAction,
75→} = actions
76→
77→// Export the reducer, either as a default or named export
78→export default reducer
79→

 1→import axios, { AxiosResponse } from 'axios'
 2→
 3→import { Restaurant } from '../types'
 4→
 5→interface BaseApi {
 6→  getRestaurants: () => Promise<Restaurant[]>
 7→  getRestaurantById: (id: string) => Promise<Restaurant>
 8→  getRestaurantsByCategory: (category: string) => Promise<Restaurant[]>
 9→}
10→
11→export const BASE_URL = 'https://mealdrop.netlify.app/.netlify/functions/restaurants'
12→
13→const isMockedEnvironment =
14→  !!import.meta.env.STORYBOOK ||
15→  import.meta.env.NODE_ENV === 'test' ||
16→  (globalThis as any).__vitest_browser__
17→
18→const apiCache = new Map()
19→
20→const apiGet = async <T>(url: string): Promise<AxiosResponse<T>> => {
21→  // do not cache when testing to avoid flakyness
22→  if (!isMockedEnvironment && apiCache.has(url)) {
23→    return apiCache.get(url)
24→  }
25→
26→  const response = await axios.get<T>(url)
27→
28→  if (!isMockedEnvironment) {
29→    apiCache.set(url, response)
30→  }
31→
32→  return response
33→}
34→
35→class RestaurantsApi implements BaseApi {
36→  async getRestaurants() {
37→    const { data: restaurants } = await apiGet<Restaurant[]>(BASE_URL)
38→
39→    return restaurants
40→  }
41→
42→  async getRestaurantById(id: string) {
43→    const { data: restaurant, status } = await apiGet<Restaurant>(`${BASE_URL}?id=${id}`)
44→
45→    if (status === 404) {
46→      throw { response: { status: 404 } }
47→    }
48→
49→    return restaurant
50→  }
51→
52→  async getRestaurantsByCategory(category: string) {
53→    const { data: restaurants } = await apiGet<Restaurant[]>(`${BASE_URL}?category=${category}`)
54→
55→    return restaurants
56→  }
57→}
58→
59→export const api = new RestaurantsApi()
