import { rootReducer } from '../src/app-state/store'
import { lightTheme } from '../src/styles/theme'
import { GlobalStyle } from '../src/styles/GlobalStyle'
import { mswHandlers } from './msw-handlers'

initialize({
  onUnhandledRequest: 'bypass',
})

const preview: Preview = {
  decorators: [
    (Story, context) => {
      const store = configureStore({ reducer: rootReducer })
      const routePath = context.parameters.routePath || '/'
      const routeEntry = context.parameters.routeEntry || '/'
      return (
        <MemoryRouter initialEntries={[routeEntry]}>
          <StoreProvider store={store}>
            <ThemeProvider theme={lightTheme}>
              <GlobalStyle />
              <Routes>
                <Route path={routePath} element={<Story />} />
              </Routes>
            </ThemeProvider>
          </StoreProvider>
        </MemoryRouter>
      )
    },
  ],
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
    msw: {
      handlers: mswHandlers,
    },
  },
}

export default preview

import type { Meta, StoryObj } from '@storybook/react-vite'
import { expect, waitFor } from 'storybook/test'

import { RestaurantDetailPage } from './RestaurantDetailPage'

const meta = {
  component: RestaurantDetailPage,
  tags: ['ai-generated'],
  parameters: {
    routePath: '/restaurants/:id',
    routeEntry: '/restaurants/1',
  },
} satisfies Meta<typeof RestaurantDetailPage>

export default meta
type Story = StoryObj<typeof meta>

export const Default: Story = {
  play: async ({ canvas }) => {
    await waitFor(() => {
      expect(canvas.getByRole('heading', { name: /burger palace/i })).toBeVisible()
    })
    await expect(canvas.getByText(/gourmet burgers/i)).toBeVisible()
  },
}

export const MenuItems: Story = {
  play: async ({ canvas }) => {
    await waitFor(() => {
      expect(canvas.getByText('Classic Burger')).toBeVisible()
    })
    await expect(canvas.getByText('Bacon Burger')).toBeVisible()
    await expect(canvas.getByText('Milkshake')).toBeVisible()
  },
}

export const Categories: Story = {
  play: async ({ canvas }) => {
    await waitFor(() => {
      expect(canvas.getByText('burgers')).toBeVisible()
    })
    await expect(canvas.getByText('comfort-food')).toBeVisible()
  },
}

import type { Meta, StoryObj } from '@storybook/react-vite'
import { expect } from 'storybook/test'

import { Spinner } from './Spinner'

const meta = {
  component: Spinner,
  tags: ['ai-generated'],
  decorators: [
    (Story) => (
      <div style={{ position: 'relative', height: '200px' }}>
        <Story />
      </div>
    ),
  ],
} satisfies Meta<typeof Spinner>

export default meta
type Story = StoryObj<typeof meta>

export const Default: Story = {
  play: async ({ canvasElement }) => {
    const svg = canvasElement.querySelector('svg')
    await expect(svg).toBeInTheDocument()
    const text = canvasElement.querySelector('svg text')
    await expect(text?.textContent).toBe('Looking for some food...')
  },
}

